"use strict";(()=>{document.addEventListener("DOMContentLoaded",()=>{let n=document.getElementById("apiUrl"),a=document.getElementById("provider"),s=document.getElementById("apiKey"),o=document.getElementById("model"),l=document.getElementById("persona"),c=document.getElementById("saveBtn"),t=document.getElementById("status");chrome.storage.sync.get(["apiUrl","provider","apiKey","model","persona"],e=>{n.value=e.apiUrl||"http://localhost:3000/api/generate",a.value=e.provider||"gemini",s.value=e.apiKey||"",o.value=e.model||"",l.value=e.persona||""}),c.addEventListener("click",()=>{let e=n.value.trim(),u=a.value,d=s.value.trim(),m=o.value.trim(),r=l.value.trim();chrome.storage.sync.set({apiUrl:e,provider:u,apiKey:d,model:m,persona:r},()=>{t.textContent="Settings saved successfully!",t.className="status success",setTimeout(()=>{t.style.display="none",t.className="status"},3e3)})})});})();
